import json

SHEET_NAME = "MXTW Asistente - Datos"

def _load_gcp_credentials_dict():
    """Devuelve (creds_dict, error_msg). Si algo falla, error_msg trae el detalle y creds_dict es None.
    Nunca lanza una excepción -- así un JSON mal formado no tumba toda la app."""
    if "gcp_service_account_json" in st.secrets:
        raw = st.secrets["gcp_service_account_json"]
        try:
            return json.loads(raw, strict=False), None
        except json.JSONDecodeError as e:
            snippet = raw[max(0, e.pos - 20):e.pos + 20].replace(chr(10), "⏎")
            return None, (f"El JSON pegado en 'gcp_service_account_json' no es válido: {e.msg} "
                           f"(línea {e.lineno}, columna {e.colno}). Alrededor del error dice: ...{snippet}...")
        except Exception as e:
            return None, f"No pude leer 'gcp_service_account_json': {e}"
    if "gcp_service_account" in st.secrets:
        try:
            return dict(st.secrets["gcp_service_account"]), None
        except Exception as e:
            return None, f"Error leyendo '[gcp_service_account]': {e}"
    return None, "No encuentro ninguna credencial de Google en Secrets (falta 'gcp_service_account_json' o '[gcp_service_account]')."

def diagnose_sheets_connection():
    creds_dict, err = _load_gcp_credentials_dict()
    if creds_dict is None:
        return False, err
    try:
        scopes = ["https://www.googleapis.com/auth/spreadsheets", "https://www.googleapis.com/auth/drive"]
        creds = Credentials.from_service_account_info(creds_dict, scopes=scopes)
        client = gspread.authorize(creds)
    except Exception as e:
        return False, f"Las credenciales no son válidas: {e}"
    try:
        sh = client.open(SHEET_NAME)
    except gspread.SpreadsheetNotFound:
        return False, f"No encuentro un Sheet llamado exactamente '{SHEET_NAME}'. Revisa el nombre (mayúsculas, espacios, guion) y que esté compartido con: {creds_dict.get('client_email', '(no encontrado)')}"
    except Exception as e:
        return False, f"Error abriendo el Sheet: {e}"
    try:
        tareas = sh.worksheet("Tareas")
        bitacora = sh.worksheet("Bitacora")
    except gspread.WorksheetNotFound as e:
        return False, f"El Sheet existe pero falta una pestaña con ese nombre exacto: {e}"
    try:
        bitacora.append_row(["TEST", "diagnóstico", "conexión de prueba desde el panel de diagnóstico"])
    except Exception as e:
        return False, f"Puedo LEER el Sheet pero no puedo ESCRIBIR en él — probablemente el permiso compartido es de 'Lector' en vez de 'Editor'. Error: {e}"
    return True, f"Conexión exitosa. Encontré {len(tareas.get_all_records())} tarea(s) registradas. Se escribió una fila de prueba en Bitacora — puedes borrarla."

