SHEET_NAME = "MXTW Asistente - Datos"

def get_gsheet_client():
    creds_dict, err = _load_gcp_credentials_dict()
    if creds_dict is None:
        return None
    try:
        scopes = ["https://www.googleapis.com/auth/spreadsheets", "https://www.googleapis.com/auth/drive"]
        creds = Credentials.from_service_account_info(creds_dict, scopes=scopes)
        return gspread.authorize(creds)
    except Exception:
        return None

def get_live_sheet_context():
    # Lee las tareas actuales y las últimas conversaciones guardadas en el Google Sheet,
    # y las suma al contexto del asistente. Si el Sheet no está conectado todavía, no rompe nada.
    client = get_gsheet_client()
    if client is None:
        return ""
    try:
        sh = client.open(SHEET_NAME)
        tasks = sh.worksheet("Tareas").get_all_records()
        log_rows = sh.worksheet("Bitacora").get_all_values()[1:]
    except Exception as e:
        return f"\n(No se pudo leer el Google Sheet en este momento: {e})"

    lines = ["\n⸻\n\nTAREAS ACTUALES (Google Sheet — fuente viva, prioriza esto sobre supuestos):"]
    if tasks:
        for t in tasks:
            lines.append(f"- [{t.get('Casa', '')}] {t.get('Tarea', '')} — Estado: {t.get('Estado', '')} — Vence: {t.get('Fecha_limite', '')}")
    else:
        lines.append("(No hay tareas registradas todavía en la pestaña Tareas.)")

    if log_rows:
        recent = log_rows[-16:]
        lines.append("\nMEMORIA DE CONVERSACIONES ANTERIORES (más recientes primero no aplica, están en orden cronológico):")
        for row in recent:
            if len(row) >= 3:
                lines.append(f"- [{row[0]}] {row[1]}: {row[2]}")

    return "\n".join(lines)

def log_to_sheet(role, message):
    # Guarda cada mensaje en la pestaña Bitácora para que el asistente "recuerde" entre sesiones.
    # Si falla (Sheet no conectado, sin permisos, etc.) no interrumpe la conversación.
    client = get_gsheet_client()
    if client is None:
        return
    try:
        sh = client.open(SHEET_NAME)
        sh.worksheet("Bitacora").append_row([datetime.now().strftime("%Y-%m-%d %H:%M"), role, message])
    except Exception:
        pass

def build_system_prompt():
    live = get_live_sheet_context()
    parts = [ROLE_PROMPT, PROJECT_DATA]
    if live:
        parts.append(live)
    return "\n".join(parts)

def call_claude():
    client = anthropic.Anthropic(api_key=st.secrets["ANTHROPIC_API_KEY"])
    history = [{"role": m["role"], "content": m["content"]} for m in st.session_state.messages if m["role"] in ["user", "assistant"]]
    if history and history[0]["role"] == "assistant":
        history = history[1:]
    response = client.messages.create(
        model="claude-sonnet-5",
        max_tokens=2000,
        system=build_system_prompt(),
        messages=history,
    )
    for block in response.content:
        if getattr(block, "type", None) == "text":
            return block.text
    return "(El modelo no devolvió texto en la respuesta. Intenta de nuevo.)"

if "messages" not in st.session_state:
    st.session_state.messages = [{"role": "assistant", "content": "Hola Pablo — soy tu asistente de producción de MXTW. ¿En qué casa o pendiente quieres que te ayude hoy?"}]

with tab_chat:
    QUICK_PROMPTS = [
        "Dame el status de hoy en una tabla corta",
        "¿Qué riesgos son más urgentes ahora mismo?",
        "Ayúdame a redactar un mensaje de status para el director general",
    ]
    st.markdown('<div class="quick-prompt-label">Preguntas rápidas</div>', unsafe_allow_html=True)
    qcols = st.columns(len(QUICK_PROMPTS))
    for i, qp in enumerate(QUICK_PROMPTS):
        if qcols[i].button(qp, key=f"quick_{i}", use_container_width=True):
            st.session_state.messages.append({"role": "user", "content": qp})
            log_to_sheet("user", qp)
            with st.spinner("Un momento..."):
                answer = call_claude()
            st.session_state.messages.append({"role": "assistant", "content": answer})
            log_to_sheet("assistant", answer)
            st.rerun()

    for m in st.session_state.messages:
        with st.chat_message(m["role"]):
            st.write(m["content"])

    user_input = st.chat_input("Pregunta sobre una casa, riesgo, fecha o pendiente...")
    if user_input:
        st.session_state.messages.append({"role": "user", "content": user_input})
        log_to_sheet("user", user_input)
        with st.chat_message("user"):
            st.write(user_input)
        with st.chat_message("assistant"):
            with st.spinner("Un momento..."):
                answer = call_claude()
                st.write(answer)
        st.session_state.messages.append({"role": "assistant", "content": answer})
        log_to_sheet("assistant", answer)


    if len(st.session_state.messages) > 1:
        report_lines = []
        for m in st.session_state.messages:
            who = "PABLO" if m["role"] == "user" else "ASISTENTE"
            report_lines.append(f"[{who}] {m['content']}")
        report_text = "MXTW — Reporte de conversación\n" + "=" * 40 + "\n\n" + "\n\n".join(report_lines)
        st.download_button("⬇️ Descargar conversación como reporte", data=report_text, file_name="mxtw_status_report.txt", mime="text/plain")

st.divider()
col1, col2, col3 = st.columns(3)
with col1: st.caption("🏗️ Head of Production")
with col2: st.caption("🗓️ Oct 26 – Nov 1, 2026")
with col3: st.caption("⬡ Hoax Empire")
st.caption("Uso interno — Mexico Tech Week 2026 (MXTW)")
